"""Multi-provider chatbot: OpenAI + Anthropic + Gemini with failover and cost tracking."""
import os
import time
import random
import uuid
from abc import ABC, abstractmethod
from collections import defaultdict
from dataclasses import dataclass, field
from typing import Generator


# ── Provider abstraction ─────────────────────────────────────────
class LLMProvider(ABC):
    @abstractmethod
    def complete(self, messages: list[dict], system: str = "", **kwargs) -> tuple[str, int, int]:
        """Returns (response_text, input_tokens, output_tokens)."""

    @abstractmethod
    def stream(self, messages: list[dict], system: str = "") -> Generator[str, None, None]:
        """Yields text chunks as they arrive."""

    @property
    @abstractmethod
    def name(self) -> str: ...


class OpenAIProvider(LLMProvider):
    def __init__(self, model: str = "gpt-4o-mini"):
        from openai import OpenAI
        self.client = OpenAI(api_key=os.environ["OPENAI_API_KEY"])
        self.model = model

    @property
    def name(self) -> str:
        return "openai"

    def complete(self, messages, system="", **kwargs) -> tuple[str, int, int]:
        all_messages = ([{"role": "system", "content": system}] if system else []) + messages
        r = self.client.chat.completions.create(
            model=self.model, messages=all_messages,
            max_tokens=kwargs.get("max_tokens", 1024),
            temperature=kwargs.get("temperature", 0.7),
        )
        return r.choices[0].message.content, r.usage.prompt_tokens, r.usage.completion_tokens

    def stream(self, messages, system="") -> Generator[str, None, None]:
        all_messages = ([{"role": "system", "content": system}] if system else []) + messages
        with self.client.chat.completions.stream(
            model=self.model, messages=all_messages, max_tokens=1024
        ) as s:
            yield from s.text_stream


class AnthropicProvider(LLMProvider):
    def __init__(self, model: str = "claude-haiku-4-5"):
        import anthropic
        self.client = anthropic.Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])
        self.model = model

    @property
    def name(self) -> str:
        return "anthropic"

    def complete(self, messages, system="", **kwargs) -> tuple[str, int, int]:
        kwargs_clean = {"model": self.model, "max_tokens": kwargs.get("max_tokens", 1024), "messages": messages}
        if system:
            kwargs_clean["system"] = system
        r = self.client.messages.create(**kwargs_clean)
        return r.content[0].text, r.usage.input_tokens, r.usage.output_tokens

    def stream(self, messages, system="") -> Generator[str, None, None]:
        kwargs = {"model": self.model, "max_tokens": 1024, "messages": messages}
        if system:
            kwargs["system"] = system
        with self.client.messages.stream(**kwargs) as s:
            yield from s.text_stream


class GeminiProvider(LLMProvider):
    def __init__(self, model: str = "gemini-2.5-flash"):
        import google.generativeai as genai
        genai.configure(api_key=os.environ["GOOGLE_API_KEY"])
        self._genai = genai
        self.model_name = model

    @property
    def name(self) -> str:
        return "google"

    def _to_gemini_messages(self, messages: list[dict]) -> list[dict]:
        role_map = {"user": "user", "assistant": "model"}
        return [{"role": role_map.get(m["role"], "user"), "parts": [m["content"]]} for m in messages if m["role"] != "system"]

    def complete(self, messages, system="", **kwargs) -> tuple[str, int, int]:
        model = self._genai.GenerativeModel(self.model_name, system_instruction=system or None)
        chat = model.start_chat(history=self._to_gemini_messages(messages[:-1]))
        r = chat.send_message(messages[-1]["content"])
        in_t  = getattr(r.usage_metadata, "prompt_token_count", 0) or 0
        out_t = getattr(r.usage_metadata, "candidates_token_count", 0) or 0
        return r.text, in_t, out_t

    def stream(self, messages, system="") -> Generator[str, None, None]:
        model = self._genai.GenerativeModel(self.model_name, system_instruction=system or None)
        last = messages[-1]["content"]
        for chunk in model.generate_content(last, stream=True):
            if chunk.text:
                yield chunk.text


# ── Conversation history ─────────────────────────────────────────
class ConversationHistory:
    def __init__(self, max_tokens: int = 50_000):
        self.messages: list[dict] = []
        self.max_tokens = max_tokens

    def add(self, role: str, content: str) -> None:
        self.messages.append({"role": role, "content": content})
        self._prune()

    def _prune(self) -> None:
        while self._token_estimate() > self.max_tokens and len(self.messages) > 2:
            self.messages.pop(0)

    def _token_estimate(self) -> int:
        return sum(len(m["content"]) // 4 for m in self.messages)

    def get(self) -> list[dict]:
        return self.messages.copy()


# ── Cost tracker ─────────────────────────────────────────────────
@dataclass
class SessionCost:
    session_id: str
    provider: str
    input_tokens: int = 0
    output_tokens: int = 0
    calls: int = 0
    RATES = {"openai": (2.50, 10.00), "anthropic": (3.00, 15.00), "google": (1.25, 10.00)}

    def record(self, inp: int, out: int) -> None:
        self.input_tokens += inp; self.output_tokens += out; self.calls += 1

    def usd(self) -> float:
        r = self.RATES.get(self.provider, (2.50, 10.00))
        return (self.input_tokens / 1e6) * r[0] + (self.output_tokens / 1e6) * r[1]

    def summary(self) -> str:
        return f"[{self.provider}] calls={self.calls} in={self.input_tokens} out={self.output_tokens} ${self.usd():.5f}"


# ── Chat session ─────────────────────────────────────────────────
class ChatSession:
    def __init__(self, providers: list[LLMProvider], system: str = "", stream: bool = False):
        self.providers = providers
        self.system = system
        self.stream_mode = stream
        self.history = ConversationHistory()
        self.cost = SessionCost(str(uuid.uuid4())[:8], providers[0].name)
        self.active_provider_idx = 0

    def _get_provider(self) -> LLMProvider:
        return self.providers[self.active_provider_idx]

    def send(self, user_message: str) -> str:
        self.history.add("user", user_message)
        messages = self.history.get()

        for i, provider in enumerate(self.providers):
            try:
                if self.stream_mode:
                    reply = ""
                    for chunk in provider.stream(messages, self.system):
                        print(chunk, end="", flush=True)
                        reply += chunk
                    print()
                    text, in_t, out_t = reply, len(" ".join(m["content"] for m in messages)) // 4, len(reply) // 4
                else:
                    text, in_t, out_t = provider.complete(messages, self.system)

                self.cost.provider = provider.name
                self.cost.record(in_t, out_t)
                self.history.add("assistant", text)
                self.active_provider_idx = i
                return text

            except Exception as e:
                print(f"[{provider.name}] failed: {e}")
                if i == len(self.providers) - 1:
                    raise RuntimeError("All providers failed")

        raise RuntimeError("All providers failed")

    def switch_provider(self, name: str) -> None:
        for i, p in enumerate(self.providers):
            if p.name == name:
                self.active_provider_idx = i
                print(f"Switched to {name}")
                return
        raise ValueError(f"Provider '{name}' not configured")


# ── CLI interface ─────────────────────────────────────────────────
def run_cli(session: ChatSession) -> None:
    print("Multi-provider chatbot | Commands: /switch <provider>, /cost, /quit")
    print(f"Active: {session._get_provider().name}")
    while True:
        try:
            user_input = input("You: ").strip()
            if not user_input:
                continue
            if user_input == "/quit":
                print(session.cost.summary())
                break
            elif user_input == "/cost":
                print(session.cost.summary())
                continue
            elif user_input.startswith("/switch "):
                session.switch_provider(user_input.split()[1])
                continue
            reply = session.send(user_input)
            if not session.stream_mode:
                print(f"AI [{session._get_provider().name}]: {reply}")
        except KeyboardInterrupt:
            print("\n" + session.cost.summary())
            break


if __name__ == "__main__":
    providers = [
        OpenAIProvider("gpt-4o-mini"),
        AnthropicProvider("claude-haiku-4-5"),
        GeminiProvider("gemini-2.5-flash"),
    ]
    session = ChatSession(
        providers=providers,
        system="You are a helpful AI assistant. Keep responses concise.",
        stream=True,
    )
    run_cli(session)

