import json, os

class PersistentChatSession(ChatSession):
    def __init__(self, providers, system='', stream=False, sessions_dir='sessions'):
        super().__init__(providers, system, stream)
        self.sessions_dir = sessions_dir
        os.makedirs(sessions_dir, exist_ok=True)

    def _session_path(self) -> str:
        return os.path.join(self.sessions_dir, f'{self.cost.session_id}.json')

    def save(self, filepath: str | None = None) -> None:
        path = filepath or self._session_path()
        data = {
            'session_id': self.cost.session_id,
            'provider': self.cost.provider,
            'system': self.system,
            'messages': self.history.messages,
            'cost': {
                'input_tokens': self.cost.input_tokens,
                'output_tokens': self.cost.output_tokens,
                'calls': self.cost.calls,
            }
        }
        with open(path, 'w') as f:
            json.dump(data, f, indent=2)

    def send(self, user_message: str) -> str:
        reply = super().send(user_message)
        self.save()  # auto-save after every turn
        return reply

    @classmethod
    def load(cls, filepath: str, providers: list) -> 'PersistentChatSession':
        with open(filepath) as f:
            data = json.load(f)
        session = cls(providers, system=data.get('system', ''))
        session.history.messages = data['messages']
        session.cost.session_id = data['session_id']
        session.cost.provider = data['provider']
        session.cost.input_tokens = data['cost']['input_tokens']
        session.cost.output_tokens = data['cost']['output_tokens']
        session.cost.calls = data['cost']['calls']
        return session

