def to_gemini_format(messages: list[dict]) -> list[dict]:
    role_map = {'user': 'user', 'assistant': 'model'}
    result = []
    for msg in messages:
        if msg['role'] == 'system':
            continue  # system handled separately in GenerativeModel(system_instruction=...)
        gemini_role = role_map.get(msg['role'])
        if gemini_role:
            result.append({'role': gemini_role, 'parts': [msg['content']]})
    return result
